INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (1, 'Arco', 'Sarca Valley', 'Italy', 'Spread along the Sarca Valley at the northern tip of Lake Garda, Arco is one of Europe''s great year-round sport-climbing hubs. Hundreds of bolted lines thread the grey and orange limestone, from slabby single-pitch warm-ups to steep, tufa-streaked testpieces and long multi-pitches on the surrounding massifs. Its sunny, sheltered aspect keeps the valley climbable through winter, while shady sectors and the cool river offer respite in summer. With its medieval castle, easy living and the famous Rockmaster festival, the town has been a climbers'' pilgrimage since the 1980s.', '2026-06-15 08:53:53.637843+00', false, 1);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (2, 'Kalymnos', 'Dodecanese', 'Greece', 'A small island in the Greek Dodecanese, Kalymnos has become a sport-climbing paradise, rising straight out of the turquoise Aegean in tiers of grey and orange limestone. Its walls drip with tufas, stalactites and pockets, giving wildly three-dimensional climbing across more than eighty sectors, most just a short scooter ride from the harbour. Grades span the full range with an unusual concentration of brilliant routes in the 6s and 7s, on rock that stays vertical to steeply overhanging. Warm spring and autumn temperatures, cheap tavernas and a relaxed island pace make it as much a holiday as a climbing trip.', '2026-06-15 08:53:53.647411+00', false, 1);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (3, 'Fontainebleau', 'Île-de-France', 'France', 'The forest of Fontainebleau, an hour south of Paris, is the spiritual home of bouldering. Thousands of sandstone blocks lie scattered through the woods, offering everything from polished classics and delicate slabs to brutal overhanging testpieces, all on rock famous for its grippy friction and rounded, sloping holds. The colour-coded circuits — graded paths linking dozens of problems — make it ideal for a full day''s roaming, whatever your level. Climbers have trained here for more than a century, and ''Font'' grades remain the benchmark for boulderers worldwide.', '2026-06-15 08:53:53.654348+00', false, 1);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (4, 'Finale Ligure', 'Liguria', 'Italy', 'Perched above the Italian Riviera in Liguria, Finale Ligure offers sunny seaside limestone with thousands of routes packed into a compact, walker-friendly area. The grey and ochre rock is riddled with pockets, tufas and the occasional fossil, giving varied climbing from gentle slabs to steep, pumpy walls — much of it climbable right through the winter. Shady caves cover the hot days, mellow grades welcome beginners, and hard projects await the obsessed, with beaches and focaccia a short drive away. It is one of Europe''s classic all-round winter destinations.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (5, 'Sperlonga', 'Lazio', 'Italy', 'Halfway between Rome and Naples, Sperlonga is a whitewashed cliff-top village fringed by beaches, with steep grey limestone crags rising just behind the town. The rock is compact and pocketed, with tufa features and a famous cave that stays dry and shaded — perfect for powerful winter sport climbing within sight of the Tyrrhenian Sea. Most routes are vertical to overhanging in the 6th and 7th grades, with quick roadside access. Roman ruins, fresh seafood and an easy swim make it a quintessential central-Italian trip.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (6, 'San Vito Lo Capo', 'Sicily', 'Italy', 'On the wild northwestern tip of Sicily, San Vito Lo Capo pairs golden limestone crags with a famous crescent of white-sand beach. Sectors range from sea-level walls to shady caves and the towering flanks of Monte Monaco, offering sun or shade in any season and grades for everyone. The rock is solid and richly featured, the winters mild, and the annual autumn climbing festival draws climbers from across Europe. Couscous, swimming and dramatic coastal scenery round out the experience.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (7, 'Val di Mello', 'Lombardy', 'Italy', 'A glacier-carved granite valley in the Italian Alps north of Milan, Val di Mello is often called ''Italy''s Yosemite''. Pristine slabs, soaring cracks and house-sized boulders rise from green meadows and clear streams, offering long trad and slab routes alongside the celebrated bouldering of the Melloblocco gathering. The climbing rewards delicate footwork and a cool head rather than raw power, and the protected valley remains gloriously car-free and unspoilt. It is at its best from late spring through autumn, when the granite is dry and the pastures bloom.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (8, 'Leonidio', 'Peloponnese', 'Greece', 'Tucked beneath towering red and grey limestone walls on the east coast of the Peloponnese, Leonidio has rapidly become one of Greece''s premier sport-climbing destinations. Hundreds of routes — many bolted within the last decade — climb immaculate tufa-streaked faces and caves across dozens of sectors above the olive groves and the sea. Grades cluster generously in the 6s and 7s, with steep, athletic lines and a growing tally of hard projects. Quiet villages, welcoming locals and mild winter sun make it a worthy rival to Kalymnos.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (9, 'Meteora', 'Thessaly', 'Greece', 'In central Greece, the otherworldly conglomerate towers of Meteora soar hundreds of metres above the plain, crowned by centuries-old monasteries. Climbing here is a serious adventure: long, often boldly protected routes ascend rounded cobbles and pebbles cemented into vertical pillars, demanding commitment and a steady head as much as technique. The traditional ethic and sparse bolting keep the crowds away and reward those seeking summits and solitude. The surreal scenery and deep history make every route a memorable outing.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (10, 'Kyparissi', 'Peloponnese', 'Greece', 'A remote seaside village on the Peloponnese coast, Kyparissi is one of Greece''s newest and most scenic climbing areas. Sectors of clean grey and orange limestone rise directly from the bay, some with belays just metres above the water, offering vertical to overhanging sport routes in a tranquil, undeveloped setting. The grades suit everyone, the rock is impeccable, and the slow rhythm of the fishing village — tavernas, clear swimming, little traffic — makes it feel like a discovery. Spring and autumn bring the finest conditions.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (11, 'Céüse', 'Hautes-Alpes', 'France', 'High on a crescent-shaped mountain above Gap in the French Alps, Céüse is regarded by many as the finest sport crag in the world. A long band of compact blue-grey limestone gives steep, sustained climbing on pockets, crimps and tufas, home to legendary hard routes like Biographie alongside brilliant lines throughout the grades. The 45-minute uphill approach and high altitude keep it cool, quiet and special, with conditions best from late spring to autumn. For many climbers a trip here is nothing short of a pilgrimage.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (12, 'Gorges du Verdon', 'Provence', 'France', 'France''s grand canyon, the Gorges du Verdon, plunges hundreds of metres to a turquoise river through sheer walls of grey limestone in Provence. It is one of Europe''s great venues for long, exposed multi-pitch climbing, with many routes reached by a committing abseil from the rim into vertical and overhanging terrain. The position is breathtaking and the climbing demanding — technical faces, tufas and the occasional bold runout — best enjoyed by confident climbers in spring and autumn. Single-pitch sectors and via ferratas round out the offering.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.crags (id, name, area, country, description, created_at, deleted, created_by) VALUES (13, 'Saint-Léger-du-Ventoux', 'Provence', 'France', 'In a quiet gorge beneath Mont Ventoux in Provence, Saint-Léger offers compact, pockety limestone prized for its technical, fingery climbing. The sheltered walls catch afternoon shade and stay climbable across much of the year, with sectors ranging from vertical pocket-pulling to a steep cave for bad weather. The grades lean towards the harder end but there is plenty for everyone, and the peaceful Provençal setting — lavender, vineyards and the looming Ventoux — adds to the charm.', '2026-06-15 11:56:48.881207+00', false, 2);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (1, 1, 'Massone', 'Arco''s most popular wall: a vast sweep of vertical to gently overhanging limestone with fast access and afternoon shade. Dozens of single-pitch routes pack the cliff, from polished slab classics to crimpy testpieces, making it the perfect place to clock up mileage.', '2026-06-15 08:53:53.640975+00', false, 1, 45.9358, 10.8861, 45.9372, 10.884);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (2, 1, 'Policromuro', 'A steep, colourful cave sector that stays dry in the rain — Arco''s go-to crag when the weather turns. Powerful, three-dimensional climbing on orange tufas, pockets and the occasional jug rewards good footwork and a strong core.', '2026-06-15 08:53:53.644854+00', false, 1, 45.9301, 10.8807, 45.9315, 10.879);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (3, 2, 'Grande Grotta', 'Kalymnos''s iconic cave: an enormous orange amphitheatre hung with giant stalactites and tufa blobs. The climbing is wildly steep and photogenic, with kneebars and rests hidden among the features — home to some of the island''s most famous routes.', '2026-06-15 08:53:53.648532+00', false, 1, 36.9961, 27.0042, 36.9948, 27.006);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (4, 2, 'Odyssey', 'Vertical to slightly overhanging grey walls with morning shade and sweeping sea views. Clean, positive holds and generous bolting make Odyssey a friendly, popular sector through the mid grades.', '2026-06-15 08:53:53.650911+00', false, 1, 37.0102, 27.0125, 37.009, 27.014);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (5, 3, 'Bas Cuvier', 'The historic heart of Fontainebleau bouldering, where many of the sport''s classic testpieces and brutal slopers were first established. Polished, technical and steeped in history, its problems still humble climbers of every level.', '2026-06-15 08:53:53.655526+00', false, 1, 48.447, 2.636, 48.4485, 2.634);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (6, 3, 'Franchard Isatis', 'A scenic Font sector of slabs, aretes and a famous traverse circuit set among the pines. The sandstone is impeccable and the problems range from delicate footwork to powerful compression.', '2026-06-15 08:53:53.658223+00', false, 1, 48.4153, 2.6479, 48.414, 2.6495);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (7, 8, 'Hot Rock', 'South-facing orange tufas high above the village, sustained and sunny. Long, athletic lines weave between hanging stalactites — a brilliant spot on cool winter days.', '2026-06-15 11:59:40.031089+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (8, 8, 'Mars', 'Vertical grey and red walls offering technical, crimpy climbing with morning shade. The holds are small and the movement precise, making it a favourite for face-climbing specialists.', '2026-06-15 11:59:40.036765+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (9, 11, 'Berlin', 'The classic introduction to Céüse''s blue limestone — vertical pockets and crimps on impeccable rock. Sustained and technical, these lines are the perfect warm-up before the cliff''s harder neighbours.', '2026-06-15 11:59:40.039771+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (10, 11, 'Biographie', 'Céüse''s most famous wall, home to some of the hardest sport pitches ever climbed, including Sharma''s Biographie. Steep, relentless and historic, it draws strong climbers from around the world.', '2026-06-15 11:59:40.04147+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (11, 4, 'Bric Pianarella', 'Sweeping seaside slabs and walls of grippy grey limestone, cooled by a sea breeze. The friendly angle and abundant edges make it one of Finale''s most enjoyable all-round sectors.', '2026-06-15 11:59:40.044352+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (12, 4, 'Grotta dell''Edera', 'A shady cave that stays dry in the rain, offering steep tufa pulling and big jugs. When the rest of Finale is wet, this is where everyone heads.', '2026-06-15 11:59:40.045911+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (13, 12, 'L''Escalès', 'The grand wall of the Verdon — long, airy limestone pitches dropping away above the gorge. Committing, exposed and unforgettable, it is the canyon''s signature multi-pitch arena.', '2026-06-15 12:03:37.148554+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (14, 12, 'Le Duc', 'Steep pockets and tufas with the turquoise river far below. The climbing is athletic and the position spectacular, with a real sense of the void beneath your heels.', '2026-06-15 12:03:37.151767+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (15, 10, 'Watermill', 'Shaded grey walls beside the spring, with clean rock and friendly grades. A relaxed, family-friendly sector ideal for warming up or escaping a hot afternoon.', '2026-06-15 12:03:37.154115+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (16, 10, 'Babala', 'Sun-soaked tufa walls overlooking the bay, steeper and more sustained than the village crags. Long, breezy lines reward endurance and a head for exposure above the sea.', '2026-06-15 12:03:37.155381+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (17, 9, 'Holy Spirit', 'An adventurous tower of rounded conglomerate cobbles, climbed on long, boldly protected pitches. Pure adventure for those with a steady head and a taste for the unusual.', '2026-06-15 12:03:37.15738+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (18, 9, 'Doupiani', 'The beginner-friendly tower near the village, with sweeping views over the monasteries and plain. Mellower pebble climbing makes it the natural place to taste Meteora''s surreal rock.', '2026-06-15 12:03:37.158531+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (19, 13, 'Le Pilier', 'Compact, pockety limestone offering technical, fingery climbing with afternoon shade. Precise footwork and a tolerance for small holds are the keys to this Saint-Léger favourite.', '2026-06-15 12:03:37.159885+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (20, 13, 'La Grotte', 'A small, steep cave that stays dry in the rain — powerful and burly. Roofs, tufas and big moves make it both the bad-weather option and a strength session in one.', '2026-06-15 12:03:37.160939+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (21, 6, 'Salinella', 'Golden limestone steps rising right behind the beach, with sea views and sun. Easy access and approachable grades make it a perfect introduction to San Vito''s rock.', '2026-06-15 12:03:37.162383+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (22, 6, 'El Bahira', 'A south-facing crag near the campsite, dry and warm through winter. Solid, featured walls with a powerful crux or two reward a midday or sunset session.', '2026-06-15 12:03:37.163295+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (23, 5, 'Grotta', 'Sperlonga''s steep, shaded sea cave — dark, powerful and dripping with tufas. The signature venue for hard winter sport climbing above the Tyrrhenian.', '2026-06-15 12:03:37.164826+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (24, 5, 'Settore Centrale', 'Vertical to gently overhanging walls with quick roadside access. Clean grey rock and a spread of mid grades make it the sector''s reliable all-rounder.', '2026-06-15 12:03:37.165764+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (25, 7, 'Scoglio delle Metamorfosi', 'Yosemite-style granite slabs and cracks rising above the valley''s meadows. Long, committing trad lines reward friction, faith and careful gear placement.', '2026-06-15 12:03:37.166992+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.sectors (id, crag_id, name, description, created_at, deleted, created_by, latitude, longitude, parking_latitude, parking_longitude) VALUES (26, 7, 'Sasso di Remenno', 'A giant freestanding granite boulder, the beating heart of the Melloblocco festival. Glassy slopers, crimps and aretes draw boulderers from across Europe.', '2026-06-15 12:03:37.16782+00', false, 2, NULL, NULL, NULL, NULL);
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (1, 'Pueblo', '6a', 'sport', 25, 'Immaculate grey slab on small crimps and pockets.', '2026-06-15 08:53:53.642294+00', 1, 1, false, 1, 1, 8, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (2, 'Spiderman', '6b+', 'sport', 28, 'Sustained vertical climbing up water-worn pockets to the headwall.', '2026-06-15 08:53:53.643885+00', 1, 1, false, 1, 1, 9, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (3, 'Policromuro', '6c', 'sport', 35, 'Relentless three-dimensional climbing up orange tufas.', '2026-06-15 08:53:53.645643+00', 1, 2, false, 1, 1, 12, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (4, 'Arcobaleno', '7a', 'sport', 22, 'Juggy overhang to a slabby finish — burly for the grade.', '2026-06-15 08:53:53.646604+00', 1, 2, false, 1, 1, 7, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (5, 'DNA', '7a', 'sport', 35, 'Wild tufa pinching through the right side of the cave.', '2026-06-15 08:53:53.649239+00', 2, 3, false, 1, 1, 12, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (6, 'Aegialis', '7b+', 'sport', 40, 'Long, pumpy stalactite climbing — read the kneebar rests or melt.', '2026-06-15 08:53:53.649986+00', 2, 3, false, 1, 1, 13, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (7, 'Priapos', '6b', 'sport', 30, 'Positive edges up a clean grey shield.', '2026-06-15 08:53:53.652315+00', 2, 4, false, 1, 1, 10, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (8, 'Monahiko Kyma', '6c+', 'sport', 32, 'Technical crux low, then jugs to the chains.', '2026-06-15 08:53:53.653493+00', 2, 4, false, 1, 1, 11, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (13, 'Pizza Fly', '6b', 'sport', 30, 'Juggy tufa warm-up with a balancy finish.', '2026-06-15 11:59:40.034777+00', 8, 7, false, 2, 1, 10, 'Sport-bolted, stainless steel, lower-off anchor');
INSERT INTO public.routes (id, name, grade, style, height_m, description, created_at, crag_id, sector_id, deleted, created_by, grading_system_id, bolt_count, protection) VALUES (14, 'Baboufo', '7a', 'sport', 35, 'Long pumpy line through hanging stalactites.', '2026-06-15 11:59:40.036061+00', 8, 7, false, 2, 1, 12, 'Sport-bolted, stainless steel, lower-off anchor');
