-- Lezendo demo seed — generated from the dev database 2026-06-15.
-- Loads demo CONTENT (users, crags, sectors, routes, images, ascents,
-- gear, forum, reviews). Assumes the schema and migration-seeded
-- reference data (grading_systems, grade_equivalencies, countries)
-- already exist in the target database.
--
-- WARNING: the TRUNCATE below wipes existing demo content first so the
-- seed is repeatable. Remove it if you want to append instead.

BEGIN;

TRUNCATE entity_reviews, forum_posts, forum_topics, gear_reviews,
  gear_items, ascents, images, routes, sectors, crags, users
  RESTART IDENTITY CASCADE;

-- ============================ users ============================
SELECT pg_catalog.setval('public.users_id_seq', 4, true);

-- ============================ crags ============================
SELECT pg_catalog.setval('public.crags_id_seq', 13, true);

-- ============================ sectors ============================
SELECT pg_catalog.setval('public.sectors_id_seq', 26, true);

-- ============================ routes ============================
SELECT pg_catalog.setval('public.routes_id_seq', 58, true);

-- ============================ images ============================
SELECT pg_catalog.setval('public.images_id_seq', 37, true);

-- ============================ ascents ============================
SELECT pg_catalog.setval('public.ascents_id_seq', 17, true);

-- ============================ gear_items ============================
SELECT pg_catalog.setval('public.gear_items_id_seq', 6, true);

-- ============================ gear_reviews ============================
SELECT pg_catalog.setval('public.gear_reviews_id_seq', 3, true);

-- ============================ forum_topics ============================
SELECT pg_catalog.setval('public.forum_topics_id_seq', 2, true);

-- ============================ forum_posts ============================
